SELECT su.age, su.nick_name as nickName, su.sex, su.phonenumber as phone, qkyd_exception.*
FROM sys_user su
JOIN qkyd_exception ON su.user_id = qkyd_exception.user_id

     and su.user_id = #{userId}
    AND su.phonenumber  like concat('%', #{phone}, '%')
    AND qkyd_exception.type = #{type}
    AND qkyd_exception.state = #{state}
    AND qkyd_exception.create_time BETWEEN #{startCreateTime} AND #{endCreateTime}

order by qkyd_exception.id desc

select id, user_id, device_id, type, value, longitude, latitude, state, create_time as readTime, update_by, update_time, update_content, location from qkyd_exception

     and user_id = #{userId}
     and create_time BETWEEN #{beginReadTime} AND #{endReadTime}

SELECT su.age, su.nick_name as nickName, su.sex, su.phonenumber as phone, qkyd_exception.id, qkyd_exception.user_id, qkyd_exception.device_id, qkyd_exception.type, qkyd_exception.value, qkyd_exception.longitude, qkyd_exception.latitude, qkyd_exception.state, qkyd_exception.create_time as readTime, qkyd_exception.update_by, qkyd_exception.update_time, qkyd_exception.update_content, qkyd_exception.location FROM sys_user su JOIN qkyd_exception ON su.user_id = qkyd_exception.user_id
AND qkyd_exception.type = #{type}
order by qkyd_exception.id desc limit 10

SELECT su.age, su.nick_name as nickName, su.sex, su.phonenumber as phone,
qkyd_exception.id, qkyd_exception.user_id as userIdWho, qkyd_exception.device_id, qkyd_exception.type, qkyd_exception.value, qkyd_exception.longitude, qkyd_exception.latitude, qkyd_exception.state, qkyd_exception.create_time as readTime, qkyd_exception.update_by as updateByWho, qkyd_exception.update_time as updateTimeWho, qkyd_exception.update_content, qkyd_exception.location
FROM sys_user su
JOIN qkyd_exception ON su.user_id = qkyd_exception.user_id

     and su.user_id = #{userId}
    AND su.phonenumber  like concat('%', #{phone}, '%')
    AND qkyd_exception.type = #{type}
    AND qkyd_exception.state = #{state}
    AND qkyd_exception.create_time BETWEEN #{startCreateTime} AND #{endCreateTime}

order by qkyd_exception.id desc

mapper.update:
update qkyd_exception
state = 1, user_id = #{userId}, device_id = #{deviceId}, type = #{type}, value = #{value}, longitude = #{longitude}, latitude = #{latitude}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime}, update_content = #{updateContent}, location = #{location},
where id = #{id}
